def game_disp(g):
    return GAME_NAMES.get(g, g.replace("_", " ").title())


def _num(x, dashes="n/a"):
    """Render a store number to 3 decimals, or a placeholder when null."""
    if x is None:
        return dashes
    if isinstance(x, (int, float)):
        return "%.3f" % x
    return str(x)


def p2_headline_fields():
    """The flat {placeholder: value} map used to fill P2 prose templates
    (blurb, E6 claim). Every value comes from SITE['headline'] / SITE['meta']."""
    h = SITE["headline"]
    m = SITE["meta"]
    return {
        "all_regime_gap": _num(h["all_regime_gap"]),
        "position_gap": _num(h["position_gap"]),
        "position_ci_lo": _num(h["position_ci"][0]),
        "position_ci_hi": _num(h["position_ci"][1]),
        "all_regime_ci_lo": _num(h["all_regime_ci"][0]),
        "all_regime_ci_hi": _num(h["all_regime_ci"][1]),
        "causal_all": _num(h["causal_all"]),
        "grad_all": _num(h["grad_all"]),
        "causal_pos": _num(h["causal_pos"]),
        "grad_pos": _num(h["grad_pos"]),
        "causal_all_n": h["causal_all_n"],
        "grad_all_n": h["grad_all_n"],
        "causal_pos_n": h["causal_pos_n"],
        "grad_pos_n": h["grad_pos_n"],
        "n_methods": m["n_methods"],
        "n_records": m["n_records"],
        "scored_games": m["scored_games"],
    }


def git_head():
    try:
        return subprocess.check_output(
            ["git", "rev-parse", "HEAD"], cwd=REPO).decode().strip()
    except Exception:
        return "main"


HEAD = git_head()
SHORT = HEAD[:8]
BLOB = M.REPO_URL + "/blob/main/"   # links track main so they survive file moves


def src(path, label=None):
    """A link to a source file in the GitHub repo."""
    if not path or path == "—":
        return html.escape(label or "—")
    label = label or path
    return '<a href="%s%s"><code>%s</code></a>' % (BLOB, path, html.escape(label))


def esc(s):
    return html.escape(str(s))


def srcln(path, line, label=None):
    """A GitHub blob link to a specific line of a source file (verified line no)."""
    label = label or ("%s:%d" % (path.rsplit("/", 1)[-1], line))
    return '<a href="%s%s#L%d"><code>%s</code></a>' % (BLOB, path, line, esc(label))


def link(href, label):
    """A link that is external (http), an internal page/anchor, or a repo path."""
    if href.startswith("http") or href.endswith(".html") or href.startswith("#") \
            or ".html#" in href:
        return '<a href="%s">%s</a>' % (href, label)
    return src(href, label)


