def _p2_format_claims(P):
    """Fill any {placeholder} in a paper's claim `value`/`detail` from the store.
    Non-P2 papers and claims without placeholders pass through unchanged."""
    if P["id"] != "paper2":
        return P["claims"]
    f = p2_headline_fields()
    out = []
    for c in P["claims"]:
        c2 = dict(c)
        for k in ("value", "detail"):
            if isinstance(c2.get(k), str) and "{" in c2[k]:
                c2[k] = c2[k].format(**f)
        out.append(c2)
    return out


