# The cross-method audit is read from the site store (docs/site_data.json),
# keyed by the SITE method key used everywhere on the pages.
def audit_row(key):
    return SITE["methods"].get(key)


def audit_faith(key):
    """(faithfulness, ci95, n_games, n_records) from the store, or None."""
    r = audit_row(key)
    if not r or r.get("F") is None:
        return None
    return (r["F"], r.get("F_ci") or 0.0, r.get("n_games"), r.get("n_records"))


def audit_triad(key):
    """(F, S, M) per-method means from the store, or None per axis where the paper
    does not define that axis. Returns None if the method has no row at all. F is
    the canonical, always-populated `faithfulness`; S and M are null for the
    black-box methods and render as n/a."""
    r = audit_row(key)
    if not r:
        return None
    return (r.get("F"), r.get("S"), r.get("M"))


def _triad_cell(val):
    """Render one triad value as a 3-decimal number, or 'n/a' when the paper does
    not define that axis for this method (null in leaderboard.json)."""
    if val is None:
        return "<span class='cite'>n/a</span>"
    return "%.3f" % val


