def _fcell(x):
    """A numeric table cell with a data-v attribute for sorting (n/a sorts last)."""
    if x is None:
        return '<td class="num" data-v="nan"><span class="cite">n/a</span></td>'
    return '<td class="num" data-v="%.4f">%.3f</td>' % (x, x)


def _method_pergame_note(F, Fpos):
    """A one-line qualitative note for a method's per-game row, where notable."""
    if F is None:
        return ""
    if Fpos is not None and Fpos <= 0.02:
        return "position gradient vanishes"
    if F >= 0.85:
        return "recovers the true causes"
    if F <= 0.05:
        return "no true-cause signal"
    if Fpos is not None and F is not None and Fpos >= 0.5 and Fpos >= F:
        return "holds up on position"
    return ""


